/**
 * AOS (Animate On Scroll) - Minimal Version
 * A lightweight library for triggering animations on scroll
 * Full version: https://github.com/michalsnik/aos
 */

const AOS = {
  init: function(options) {
    this.options = Object.assign({
      duration: 1000,
      offset: 100,
      once: false,
      easing: 'ease-in-out'
    }, options);
    
    this.observeElements();
    window.addEventListener('scroll', () => this.observeElements());
  },
  
  observeElements: function() {
    const elements = document.querySelectorAll('[data-aos]');
    elements.forEach(el => {
      if (!el.hasAttribute('data-aos-animated')) {
        const rect = el.getBoundingClientRect();
        if (rect.top < window.innerHeight - this.options.offset) {
          el.setAttribute('data-aos-animated', 'true');
          this.triggerAnimation(el);
        }
      }
    });
  },
  
  triggerAnimation: function(element) {
    const animation = element.getAttribute('data-aos');
    const duration = element.getAttribute('data-aos-duration') || this.options.duration;
    
    element.style.animation = `${animation} ${duration}ms ${this.options.easing}`;
    element.style.opacity = '1';
  },
  
  refresh: function() {
    document.querySelectorAll('[data-aos-animated]').forEach(el => {
      el.removeAttribute('data-aos-animated');
      el.style.animation = '';
    });
    this.observeElements();
  }
};

// Export for use
if (typeof window !== 'undefined') {
  window.AOS = AOS;
}
